<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Personal Expense Tracker</title>
  <style>
    * { box-sizing: border-box; }
    body { font-family: system-ui, sans-serif; max-width: 700px; margin: 2rem auto; padding: 0 1rem; line-height: 1.5; }
    h1 { margin-bottom: 1.5rem; }
    .form-row { display: flex; gap: 0.5rem; flex-wrap: wrap; margin-bottom: 0.75rem; align-items: flex-end; }
    .form-row label { font-weight: 600; min-width: 80px; }
    .form-row input, .form-row select { padding: 0.5rem; border: 1px solid #ccc; border-radius: 4px; font-size: 1rem; }
    .form-row input[type="number"] { width: 100px; }
    .form-row input[type="date"] { width: 160px; }
    .form-row select { width: 140px; }
    .form-row input[name="note"] { flex: 1; min-width: 200px; }
    button#add-expense { padding: 0.6rem 1.2rem; background: #2563eb; color: white; border: none; border-radius: 4px; cursor: pointer; font-size: 1rem; }
    button#add-expense:hover { background: #1d4ed8; }
    #form-error { color: #dc2626; margin-top: 0.5rem; min-height: 1.25rem; }
    .filters { display: flex; gap: 1rem; flex-wrap: wrap; margin: 1.5rem 0; padding: 1rem; background: #f8fafc; border-radius: 6px; }
    .filters label { display: flex; flex-direction: column; gap: 0.25rem; font-size: 0.875rem; }
    .filters select, .filters input { padding: 0.4rem; border: 1px solid #ccc; border-radius: 4px; }
    .expense-list { border-top: 1px solid #e5e7eb; padding-top: 1rem; }
    .expense { display: flex; justify-content: space-between; align-items: center; padding: 0.75rem 0; border-bottom: 1px solid #f1f5f9; gap: 1rem; flex-wrap: wrap; }
    .expense:last-child { border-bottom: none; }
    .expense-info { display: flex; flex-direction: column; gap: 0.25rem; flex: 1; min-width: 200px; }
    .expense-main { display: flex; gap: 1rem; align-items: baseline; flex-wrap: wrap; }
    .expense-amount { font-weight: 600; color: #dc2626; }
    .expense-category { background: #e0e7ff; color: #3730a3; padding: 0.125rem 0.5rem; border-radius: 9999px; font-size: 0.75rem; font-weight: 600; text-transform: capitalize; }
    .expense-date { color: #64748b; font-size: 0.875rem; }
    .expense-note { color: #475569; font-size: 0.875rem; }
    .exp-del { background: #fee2e2; color: #dc2626; border: none; padding: 0.35rem 0.75rem; border-radius: 4px; cursor: pointer; font-size: 0.875rem; white-space: nowrap; }
    .exp-del:hover { background: #fecaca; }
    .summary { margin-top: 1.5rem; padding: 1rem; background: #f8fafc; border-radius: 6px; }
    .summary-row { display: flex; justify-content: space-between; padding: 0.4rem 0; }
    .summary-row.total { border-top: 2px solid #e5e7eb; margin-top: 0.5rem; padding-top: 0.75rem; font-weight: 700; font-size: 1.125rem; }
    .cat-totals { display: flex; flex-wrap: wrap; gap: 1rem; margin-top: 0.75rem; }
    .cat-total { background: white; padding: 0.5rem 1rem; border-radius: 4px; border: 1px solid #e5e7eb; font-size: 0.875rem; }
    .cat-total[data-cat="groceries"] { border-left: 3px solid #22c55e; }
    .cat-total[data-cat="transport"] { border-left: 3px solid #3b82f6; }
    .cat-total[data-cat="bills"] { border-left: 3px solid #f59e0b; }
    .cat-total[data-cat="fun"] { border-left: 3px solid #ec4899; }
    .empty-state { text-align: center; color: #94a3b8; padding: 2rem; }
  </style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <form id="expense-form">
    <div class="form-row">
      <label for="amount">Amount</label>
      <input type="number" id="amount" name="amount" step="0.01" min="0.01" placeholder="0.00" required>
    </div>
    <div class="form-row">
      <label for="category">Category</label>
      <select id="category" name="category" required>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </div>
    <div class="form-row">
      <label for="date">Date</label>
      <input type="date" id="date" name="date" required>
    </div>
    <div class="form-row">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" name="note" placeholder="e.g. Weekly shop">
    </div>
    <button type="submit" id="add-expense">Add Expense</button>
    <div id="form-error"></div>
  </form>

  <div class="filters">
    <label>
      Category
      <select id="filter-category">
        <option value="all">All</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </label>
    <label>
      From
      <input type="date" id="filter-from">
    </label>
    <label>
      To
      <input type="date" id="filter-to">
    </label>
  </div>

  <div class="expense-list" id="expense-list">
    <div class="empty-state">No expenses recorded yet.</div>
  </div>

  <div class="summary">
    <div class="summary-row total">
      <span>Total</span>
      <span id="total">0.00</span>
    </div>
    <div class="cat-totals" id="cat-totals">
      <div class="cat-total" data-cat="groceries">Groceries: 0.00</div>
      <div class="cat-total" data-cat="transport">Transport: 0.00</div>
      <div class="cat-total" data-cat="bills">Bills: 0.00</div>
      <div class="cat-total" data-cat="fun">Fun: 0.00</div>
    </div>
  </div>

  <script>
    const STORAGE_KEY = 'expenses_v1';
    const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

    let expenses = [];

    const $ = (sel) => document.querySelector(sel);
    const $$ = (sel) => document.querySelectorAll(sel);

    const form = $('#expense-form');
    const amountInput = $('#amount');
    const categoryInput = $('#category');
    const dateInput = $('#date');
    const noteInput = $('#note');
    const errorEl = $('#form-error');
    const listEl = $('#expense-list');
    const totalEl = $('#total');
    const filterCategory = $('#filter-category');
    const filterFrom = $('#filter-from');
    const filterTo = $('#filter-to');

    function loadExpenses() {
      try {
        const stored = localStorage.getItem(STORAGE_KEY);
        if (stored) {
          expenses = JSON.parse(stored);
        }
      } catch (e) {
        expenses = [];
      }
      // Ensure each expense has an id
      expenses.forEach((e, i) => {
        if (!e.id) e.id = Date.now() + i;
      });
    }

    function saveExpenses() {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    }

    function formatCurrency(val) {
      return val.toFixed(2);
    }

    function createExpenseRow(expense) {
      const row = document.createElement('div');
      row.className = 'expense';
      row.dataset.id = expense.id;

      const categoryLabel = expense.category.charAt(0).toUpperCase() + expense.category.slice(1);

      row.innerHTML = `
        <div class="expense-info">
          <div class="expense-main">
            <span class="expense-amount">${formatCurrency(expense.amount)}</span>
            <span class="expense-category">${categoryLabel}</span>
            <span class="expense-date">${expense.date}</span>
          </div>
          ${expense.note ? `<div class="expense-note">${escapeHtml(expense.note)}</div>` : ''}
        </div>
        <button class="exp-del" type="button">Delete</button>
      `;

      row.querySelector('.exp-del').addEventListener('click', () => deleteExpense(expense.id));
      return row;
    }

    function escapeHtml(text) {
      const div = document.createElement('div');
      div.textContent = text;
      return div.innerHTML;
    }

    function renderExpenses() {
      const filtered = getFilteredExpenses();
      listEl.innerHTML = '';

      if (filtered.length === 0) {
        listEl.innerHTML = '<div class="empty-state">No expenses match the current filters.</div>';
      } else {
        filtered.forEach(expense => {
          listEl.appendChild(createExpenseRow(expense));
        });
      }
      updateTotals(filtered);
    }

    function getFilteredExpenses() {
      const cat = filterCategory.value;
      const from = filterFrom.value ? new Date(filterFrom.value) : null;
      const to = filterTo.value ? new Date(filterTo.value) : null;

      return expenses
        .filter(e => {
          if (cat !== 'all' && e.category !== cat) return false;
          const d = new Date(e.date);
          if (from && d < from) return false;
          if (to && d > to) return false;
          return true;
        })
        .sort((a, b) => new Date(b.date) - new Date(a.date) || b.id - a.id);
    }

    function updateTotals(filteredExpenses) {
      const total = filteredExpenses.reduce((sum, e) => sum + e.amount, 0);
      totalEl.textContent = formatCurrency(total);

      CATEGORIES.forEach(cat => {
        const catTotal = filteredExpenses
          .filter(e => e.category === cat)
          .reduce((sum, e) => sum + e.amount, 0);
        const el = $(`.cat-total[data-cat="${cat}"]`);
        if (el) {
          el.textContent = `${cat.charAt(0).toUpperCase() + cat.slice(1)}: ${formatCurrency(catTotal)}`;
        }
      });
    }

    function addExpense(data) {
      const expense = {
        id: Date.now(),
        amount: parseFloat(data.amount),
        category: data.category,
        date: data.date,
        note: data.note || ''
      };
      expenses.unshift(expense);
      saveExpenses();
      renderExpenses();
    }

    function deleteExpense(id) {
      expenses = expenses.filter(e => e.id !== id);
      saveExpenses();
      renderExpenses();
    }

    function validateForm(formData) {
      const amount = parseFloat(formData.get('amount'));
      const date = formData.get('date');

      if (isNaN(amount) || amount <= 0) {
        return 'Please enter a valid positive amount.';
      }
      if (!date) {
        return 'Please select a date.';
      }
      return null;
    }

    // Event listeners
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      const formData = new FormData(form);
      const error = validateForm(formData);

      if (error) {
        errorEl.textContent = error;
        return;
      }

      errorEl.textContent = '';
      addExpense(Object.fromEntries(formData));
      amountInput.value = '';
      noteInput.value = '';
      amountInput.focus();
    });

    [filterCategory, filterFrom, filterTo].forEach(el => {
      el.addEventListener('change', renderExpenses);
      el.addEventListener('input', renderExpenses);
    });

    // Set default date to today
    const today = new Date().toISOString().split('T')[0];
    dateInput.value = today;

    // Initialize
    loadExpenses();
    renderExpenses();
  </script>
</body>
</html>
